// Unit 23 — Le Monde du Travail
// Work culture and professional French

export default {n:23,lang:"fr",srcLang:"en",track:"v2",title:"Le Monde du Travail",sub:"Work culture and professional French",icon:"💼",level:"B1.7",color:"#7B5EE8",lessons:[
  {id:"fre23l1",title:"Au travail",icon:"💼",xp:15,board:true,steps:[
        {type:"intro",title:"Au travail",desc:"Learn essential job vocabulary for professional life in France.",goals:["Name common workplace nouns","Use articles correctly with job vocabulary","Discuss work in simple sentences"]},
        {type:"teach",trg:"l'emploi (m.)",src:"the job / employment",pos:"noun",gender:"m",phonetic:"lon-PLWAH",note:"Masculine noun. L' hides the gender.\nUn emploi = a job, l'emploi = the job.",example:"A: Tu as trouvé un emploi?\nB: Oui, j'ai un emploi dans une banque.\nA: C'est un emploi à temps plein?\nB: Oui, à temps plein depuis janvier.",exampleSrc:"A: Did you find a job?\nB: Yes, I have a job at a bank.\nA: Is it a full-time job?\nB: Yes, full-time since January.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"le poste",src:"the position / role",pos:"noun",gender:"m",phonetic:"luh POST",note:"Masculine. Le poste = the position.\nDo not confuse with la poste (the post office).",example:"A: Quel poste occupez-vous?\nB: J'occupe le poste de directeur commercial.\nA: C'est un poste intéressant?\nB: Oui, très varié et stimulant.",exampleSrc:"A: What position do you hold?\nB: I hold the position of sales director.\nA: Is it an interesting position?\nB: Yes, very varied and stimulating.",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"teach",trg:"l'entreprise (f.)",src:"the company / business",pos:"intj",gender:null,phonetic:"lon-truh-PREEZ",note:"Feminine. Une entreprise = a company.\nAlso means undertaking or venture.",example:"A: Dans quelle entreprise travailles-tu?\nB: Je travaille dans une grande entreprise.\nA: Combien de personnes y travaillent?\nB: Environ cinq cents personnes.",exampleSrc:"A: Which company do you work at?\nB: I work at a large company.\nA: How many people work there?\nB: About five hundred people.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"teach",trg:"le bureau",src:"the office / desk",pos:"noun",gender:"m",phonetic:"luh bew-ROH",note:"Masculine. Means both office (room) and desk.\nAu bureau = at the office.",example:"A: Ton bureau est grand?\nB: Non, c'est un petit bureau partagé.\nA: Tu aimes travailler au bureau?\nB: Je préfère le télétravail, honnêtement.",exampleSrc:"A: Is your office big?\nB: No, it's a small shared office.\nA: Do you like working at the office?\nB: I prefer working from home, honestly.",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"teach",trg:"le/la collègue",src:"the colleague",pos:"intj",gender:null,phonetic:"luh/lah ko-LEG",note:"Both masculine and feminine.\nUn collègue (male), une collègue (female).",example:"A: Tu t'entends bien avec tes collègues?\nB: Oui, j'ai des collègues très sympas.\nA: Vous déjeunez ensemble?\nB: Oui, presque tous les jours.",exampleSrc:"A: Do you get along well with your colleagues?\nB: Yes, I have very nice colleagues.\nA: Do you have lunch together?\nB: Yes, almost every day.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"teach",trg:"le patron / la patronne",src:"the boss",pos:"noun",gender:"m",phonetic:"luh pa-TRON / lah pa-TRON",note:"Masculine: le patron. Feminine: la patronne.\nAlso means owner of a business.",example:"A: Comment est ton patron?\nB: Ma patronne est très exigeante mais juste.\nA: Elle travaille beaucoup?\nB: Oui, elle est toujours la première au bureau.",exampleSrc:"A: What is your boss like?\nB: My boss is very demanding but fair.\nA: Does she work a lot?\nB: Yes, she is always the first at the office.",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"teach",trg:"le salaire",src:"the salary",pos:"noun",gender:"m",phonetic:"luh sa-LEHR",note:"Masculine. Le salaire = the salary.\nUne augmentation de salaire = a raise.",example:"A: Tu es satisfait de ton salaire?\nB: Le salaire est correct pour un débutant.\nA: Il y a des augmentations prévues?\nB: Oui, chaque année en janvier.",exampleSrc:"A: Are you satisfied with your salary?\nB: The salary is fair for a beginner.\nA: Are there planned raises?\nB: Yes, every year in January.",funFact:"Cognate with English 'salary'. Many English words were borrowed from French after 1066."},
        {type:"mc",q:"How do you say 'the company' in French?",opts:["l'entreprise","le bureau","le poste","le salaire"],ans:"l'entreprise",hint:"Think of where many people work together as a business"},
        {type:"mc",q:"Le bureau can mean both ___ and ___.",opts:["salary and job","office and desk","boss and colleague","company and position"],ans:"office and desk",hint:"Two meanings for the same word, both in a workspace"},
        {type:"fb",opts:["collègue","patron","salaire","bureau"],hint:"A person you work with at the same level",s:"Mon {1} est très sympa, on déjeune ensemble.",a:["collègue"]},
        {type:"fb",opts:["emploi","bureau","salaire","patron"],hint:"General word for a paid occupation",s:"Elle a trouvé un {1} dans une banque.",a:["emploi"]},
        {type:"mc",q:"Which word means 'the salary'?",opts:["le poste","le patron","le salaire","le collègue"],ans:"le salaire",hint:"Related to the money you earn monthly"},
        {type:"match",pairs:[{trg:"l'emploi",src:"the job"},{trg:"le poste",src:"the position"},{trg:"le bureau",src:"the office"},{trg:"le patron",src:"the boss"},{trg:"le salaire",src:"the salary"}]},
        {type:"fb",opts:["poste","emploi","bureau","salaire"],hint:"Asking about someone's specific role or title",s:"Quel {1} occupez-vous dans cette entreprise?",a:["poste"]},
        {type:"mc",q:"'La patronne' is the feminine form of which word?",opts:["le collègue","le bureau","le poste","le patron"],ans:"le patron",hint:"The person who runs the business or team"},
        {type:"fb",opts:["entreprise","bureau","emploi","collègue"],hint:"A large organization with many employees",s:"Je travaille dans une grande {1} à Paris.",a:["entreprise"]},
        {type:"mc",q:"Which sentence correctly uses 'au bureau'?",opts:["Je vais au bureau chaque matin.","Je vais au patron chaque matin.","Je vais au salaire chaque matin.","Je vais au collègue chaque matin."],ans:"Je vais au bureau chaque matin.",hint:"Going to a physical workplace location"}
  ]},
  {id:"fre23l2",title:"Chercher un emploi",icon:"📄",xp:15,board:true,steps:[
        {type:"intro",title:"Chercher un emploi",desc:"Master vocabulary for job applications and interviews in France.",goals:["Discuss job applications","Use application vocabulary","Talk about the hiring process"]},
        {type:"teach",trg:"la candidature",src:"the application",pos:"noun",gender:"f",phonetic:"lah kan-dee-da-TEWR",note:"Feminine. Poser sa candidature = to apply.\nUne candidature spontanée = unsolicited application.",example:"A: Tu as envoyé ta candidature?\nB: Oui, j'ai envoyé ma candidature hier.\nA: Pour quel poste?\nB: Pour un poste de chef de projet.",exampleSrc:"A: Did you send your application?\nB: Yes, I sent my application yesterday.\nA: For which position?\nB: For a project manager position.",funFact:"Feminine noun. Words ending in -tion, -sion, -ure are usually feminine."},
        {type:"teach",trg:"postuler",src:"to apply (for a job)",pos:"verb",gender:null,phonetic:"pos-tew-LAY",note:"Regular -er verb. Postuler pour/a = apply for.\nJe postule, tu postules, il postule.",example:"A: Tu vas postuler pour ce poste?\nB: Oui, je vais postuler cette semaine.\nA: Il faut envoyer quoi?\nB: Un CV et une lettre de motivation.",exampleSrc:"A: Are you going to apply for this position?\nB: Yes, I'm going to apply this week.\nA: What do you need to send?\nB: A CV and a cover letter.",funFact:"A regular -er verb, the most common French verb group (~90% of all verbs)."},
        {type:"teach",trg:"l'entretien (m.)",src:"the interview",pos:"intj",gender:null,phonetic:"lon-truh-TYAN",note:"Masculine. Un entretien d'embauche = job interview.\nAlso means conversation or maintenance.",example:"A: Quand est ton entretien?\nB: Mon entretien est jeudi matin.\nA: Tu es prêt?\nB: J'ai préparé mes réponses, oui.",exampleSrc:"A: When is your interview?\nB: My interview is Thursday morning.\nA: Are you ready?\nB: I've prepared my answers, yes.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"teach",trg:"embaucher",src:"to hire",pos:"verb",gender:null,phonetic:"on-boh-SHAY",note:"Regular -er verb. Embaucher = to hire.\nOpposite: licencier = to fire/lay off.",example:"A: L'entreprise va embaucher quelqu'un?\nB: Oui, ils veulent embaucher deux personnes.\nA: Quand commencent-ils?\nB: En septembre, après les vacances.",exampleSrc:"A: Is the company going to hire someone?\nB: Yes, they want to hire two people.\nA: When do they start?\nB: In September, after the holidays.",funFact:"A regular -er verb, the most common French verb group (~90% of all verbs)."},
        {type:"teach",trg:"le CV",src:"the CV / resume",pos:"noun",gender:"m",phonetic:"luh say-VAY",note:"Masculine. Pronounced as letters: say-vay.\nShort for curriculum vitae.\nFrench CVs include a photo.",example:"A: Tu as mis à jour ton CV?\nB: Oui, j'ai ajouté mon dernier emploi.\nA: Il fait combien de pages?\nB: En France, une page suffit généralement.",exampleSrc:"A: Did you update your CV?\nB: Yes, I added my last job.\nA: How many pages is it?\nB: In France, one page is usually enough.",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"teach",trg:"la lettre de motivation",src:"the cover letter",pos:"noun",gender:"f",phonetic:"lah LET-ruh duh mo-tee-va-SYON",note:"Feminine. Literally: letter of motivation.\nAlways required with a CV in France.",example:"A: Ta lettre de motivation est prête?\nB: Presque, je dois la relire.\nA: Elle est longue?\nB: Non, une page maximum.",exampleSrc:"A: Is your cover letter ready?\nB: Almost, I need to proofread it.\nA: Is it long?\nB: No, one page maximum.",funFact:"Feminine noun. Words ending in -tion, -sion, -ure are usually feminine."},
        {type:"mc",q:"What does 'postuler' mean?",opts:["to apply for a job","to hire someone","to resign","to promote"],ans:"to apply for a job",hint:"The action a ___ seeker takes when interested in a role"},
        {type:"fb",opts:["candidature","entretien","salaire","emploi"],hint:"The complete package you send when applying",s:"J'ai envoyé ma {1} pour le poste de comptable.",a:["candidature"]},
        {type:"mc",q:"What is 'un entretien d'embauche'?",opts:["a work meeting","a job interview","a salary negotiation","a resignation letter"],ans:"a job interview",hint:"A formal conversation before getting hired"},
        {type:"fb",opts:["embaucher","postuler","travailler","organiser"],hint:"The action a company takes to bring in new staff",s:"L'entreprise va {1} trois nouveaux employés.",a:["embaucher"]},
        {type:"match",pairs:[{trg:"la candidature",src:"the application"},{trg:"postuler",src:"to apply"},{trg:"l'entretien",src:"the interview"},{trg:"embaucher",src:"to hire"},{trg:"le CV",src:"the resume"}]},
        {type:"mc",q:"In France, a CV typically should be:",opts:["only digital","three pages minimum","one page with a photo","written by hand"],ans:"one page with a photo",hint:"French conventions differ from many other countries"},
        {type:"fb",opts:["lettre","candidature","page","entreprise"],hint:"A written document that accompanies your resume",s:"Tu dois écrire une {1} de motivation pour accompagner ton CV.",a:["lettre"]},
        {type:"mc",q:"What is the opposite of 'embaucher'?",opts:["organiser","postuler","travailler","licencier"],ans:"licencier",hint:"When a company lets someone go from their role"},
        {type:"fb",opts:["entretien","emploi","bureau","salaire"],hint:"A scheduled formal conversation with a potential employer",s:"Mon {1} est jeudi à quatorze heures.",a:["entretien"]},
        {type:"fb",opts:["candidature","réunion","entreprise","salaire"],hint:"The feminine noun meaning 'application' for a job opening.",s:"J'ai envoyé ma {1} hier pour le poste de directeur.",a:["candidature"]},
        {type:"mc",q:"Which sentence correctly uses 'postuler'?",opts:["Je vais postuler pour ce poste.","Je vais postuler mon patron.","Je vais postuler le bureau.","Je vais postuler une réunion."],ans:"Je vais postuler pour ce poste.",hint:"This verb requires a preposition before the role"}
  ]},
  {id:"fre23l3",title:"La vie au bureau",icon:"🏢",xp:15,board:true,steps:[
        {type:"intro",title:"La vie au bureau",desc:"Learn vocabulary for daily office activities, meetings, and projects.",goals:["Describe office activities","Discuss meetings and deadlines","Use project management vocabulary"]},
        {type:"teach",trg:"la réunion",src:"the meeting",pos:"noun",gender:"f",phonetic:"lah ray-ew-NYON",note:"Feminine. Une réunion = a meeting.\nEn réunion = in a meeting.",example:"A: Tu as une réunion cet après-midi?\nB: Oui, une réunion avec toute l'équipe.\nA: Elle dure combien de temps?\nB: Normalement une heure, parfois plus.",exampleSrc:"A: Do you have a meeting this afternoon?\nB: Yes, a meeting with the whole team.\nA: How long does it last?\nB: Usually one hour, sometimes more.",funFact:"Feminine noun. Words ending in -tion, -sion, -ure are usually feminine."},
        {type:"teach",trg:"le rapport",src:"the report",pos:"noun",gender:"m",phonetic:"luh ra-POR",note:"Masculine. Le rapport = the report.\nRédiger un rapport = to write a report.",example:"A: Tu as fini ton rapport?\nB: Non, je dois encore le relire.\nA: C'est pour quand?\nB: Le rapport est pour vendredi.",exampleSrc:"A: Did you finish your report?\nB: No, I still need to proofread it.\nA: When is it due?\nB: The report is due Friday.",funFact:"Cognate with English 'report'. Many English words were borrowed from French after 1066."},
        {type:"teach",trg:"le dossier",src:"the file / folder / case",pos:"noun",gender:"m",phonetic:"luh do-SYAY",note:"Masculine. Physical folder or digital file.\nAlso means a case or project file.",example:"A: Où est le dossier du client?\nB: Il est sur mon bureau, dans le tiroir.\nA: Tu peux me l'envoyer par mail?\nB: Oui, je te l'envoie tout de suite.",exampleSrc:"A: Where is the client's file?\nB: It's on my desk, in the drawer.\nA: Can you send it to me by email?\nB: Yes, I'll send it to you right away.",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"teach",trg:"le délai",src:"the deadline / timeframe",pos:"noun",gender:"m",phonetic:"luh day-LAY",note:"Masculine. Le délai = the deadline/timeframe.\nRespecter le délai = to meet the deadline.",example:"A: Quel est le délai pour ce projet?\nB: Le délai est de deux semaines.\nA: C'est suffisant?\nB: C'est serré, mais on va y arriver.",exampleSrc:"A: What is the deadline for this project?\nB: The deadline is two weeks.\nA: Is that enough?\nB: It's tight, but we'll manage.",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"teach",trg:"le projet",src:"the project",pos:"noun",gender:"m",phonetic:"luh pro-ZHAY",note:"Masculine. Le projet = the project.\nChef de projet = project manager.",example:"A: Comment avance le projet?\nB: Le projet avance bien, on est dans les temps.\nA: Il reste beaucoup à faire?\nB: Non, on est presque à la fin.",exampleSrc:"A: How is the project going?\nB: The project is going well, we're on schedule.\nA: Is there much left to do?\nB: No, we're almost at the end.",funFact:"Cognate with English 'project'. Many English words were borrowed from French after 1066."},
        {type:"teach",trg:"le planning",src:"the schedule / plan",pos:"noun",gender:"m",phonetic:"luh pla-NING",note:"Masculine. Borrowed from English but fully French.\nLe planning = the schedule/timetable.",example:"A: Tu as regardé le planning de la semaine?\nB: Oui, on a trois réunions et deux délais.\nA: C'est chargé!\nB: Comme d'habitude en fin de mois.",exampleSrc:"A: Did you check the week's schedule?\nB: Yes, we have three meetings and two deadlines.\nA: That's busy!\nB: As usual at the end of the month.",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"mc",q:"What does 'le délai' mean?",opts:["the deadline","the delay","the project","the meeting"],ans:"the deadline",hint:"The time limit by which something must be completed"},
        {type:"fb",opts:["réunion","rapport","dossier","projet"],hint:"A scheduled gathering where the team discusses work",s:"Nous avons une {1} avec le directeur à dix heures.",a:["réunion"]},
        {type:"mc",q:"Which word means 'the report'?",opts:["le dossier","le rapport","le projet","le planning"],ans:"le rapport",hint:"A written document summarizing findings or progress"},
        {type:"fb",opts:["dossier","rapport","délai","planning"],hint:"A folder containing all documents about one topic",s:"Le {1} du client est dans l'armoire.",a:["dossier"]},
        {type:"match",pairs:[{trg:"la réunion",src:"the meeting"},{trg:"le rapport",src:"the report"},{trg:"le dossier",src:"the file"},{trg:"le délai",src:"the deadline"},{trg:"le projet",src:"the project"}]},
        {type:"mc",q:"'Chef de projet' means:",opts:["project report","project deadline","project manager","project meeting"],ans:"project manager",hint:"The person responsible for leading a work initiative"},
        {type:"fb",opts:["délai","projet","rapport","planning"],hint:"The time limit you cannot exceed",s:"Il faut respecter le {1}, c'est pour vendredi.",a:["délai"]},
        {type:"mc",q:"Which sentence is correct?",opts:["Je suis en planning, je rappelle plus tard.","Je suis en rapport, je rappelle plus tard.","Je suis en dossier, je rappelle plus tard.","Je suis en réunion, je rappelle plus tard."],ans:"Je suis en réunion, je rappelle plus tard.",hint:"When you cannot answer the phone because of a group gathering"},
        {type:"fb",opts:["rapport","bureau","congé","patron"],hint:"The masculine document you write summarizing findings or progress.",s:"Le {1} doit être rendu avant vendredi.",a:["rapport"]},
        {type:"mc",q:"'Nous avons un ___ serré pour ce projet.' What fills the blank?",opts:["délai","salaire","bureau","emploi"],ans:"délai",hint:"The masculine noun meaning 'deadline' when time is running out."},
        {type:"fb",opts:["projet","rapport","dossier","planning"],hint:"A large work initiative with multiple tasks and goals",s:"Le {1} avance bien, on finira avant le délai.",a:["projet"]}
  ]},
  {id:"fre23l4",title:"L'email professionnel",icon:"📧",xp:15,board:true,steps:[
        {type:"intro",title:"L'email professionnel",desc:"Master the art of writing professional emails in French.",goals:["Write formal email openings and closings","Use standard professional phrases","Understand French email etiquette"]},
        {type:"teach",trg:"Madame, Monsieur,",src:"Dear Sir/Madam,",pos:"intj",gender:null,phonetic:"ma-DAM, muh-SYUH",note:"Standard formal greeting for unknown recipients.\nAlways with a comma after.",example:"A: Comment commence-t-on un email formel?\nB: On écrit Madame, Monsieur si on ne connaît pas le destinataire.\nA: Et si on connaît la personne?\nB: On écrit Cher Monsieur Dupont ou Chère Madame Martin.",exampleSrc:"A: How do you start a formal email?\nB: You write Dear Sir/Madam if you don't know the recipient.\nA: And if you know the person?\nB: You write Dear Mr. Dupont or Dear Mrs. Martin.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"teach",trg:"Cordialement",src:"Kind regards",pos:"noun",gender:null,phonetic:"kor-dyal-MAWN",note:"The most common professional email closing.\nNeutral and appropriate for all contexts.",example:"A: Comment termine-t-on un email professionnel?\nB: Le plus courant, c'est Cordialement.\nA: C'est assez formel?\nB: Oui, c'est parfait pour la plupart des situations.",exampleSrc:"A: How do you end a professional email?\nB: The most common is Kind regards.\nA: Is it formal enough?\nB: Yes, it's perfect for most situations.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"Je vous prie d'agréer mes salutations distinguées",src:"Yours faithfully (very formal closing)",pos:"verb",gender:null,phonetic:"zhuh voo PREE da-gray-AY may sa-lew-ta-SYON dees-tan-GAY",note:"Very formal closing for official correspondence.\nUsed in cover letters and formal requests.",example:"A: Cette formule est très longue!\nB: Oui, c'est la formule la plus formelle.\nA: On l'utilise souvent?\nB: Pour les lettres officielles et les candidatures.",exampleSrc:"A: This formula is very long!\nB: Yes, it's the most formal formula.\nA: Do you use it often?\nB: For official letters and job applications.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"teach",trg:"Veuillez trouver ci-joint",src:"Please find attached",pos:"intj",gender:null,phonetic:"vuh-YAY troo-VAY see-ZHWAN",note:"Standard phrase for email attachments.\nVeuillez = please (formal imperative of vouloir).",example:"A: Comment dire qu'il y a une pièce jointe?\nB: On écrit: Veuillez trouver ci-joint mon CV.\nA: C'est toujours au masculin, ci-joint?\nB: Avant le nom, oui. Après, il s'accorde.",exampleSrc:"A: How do you say there's an attachment?\nB: You write: Please find attached my CV.\nA: Is ci-joint always masculine?\nB: Before the noun, yes. After, it agrees.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"teach",trg:"Suite à notre conversation",src:"Following our conversation",pos:"intj",gender:null,phonetic:"sweet ah notr kon-ver-sa-SYON",note:"Common opening for follow-up emails.\nSuite a = following, as a result of.",example:"A: Comment commencer après un appel téléphonique?\nB: On écrit: Suite à notre conversation téléphonique...\nA: Et ensuite?\nB: On rappelle le sujet de la discussion.",exampleSrc:"A: How do you start after a phone call?\nB: You write: Following our phone conversation...\nA: And then?\nB: You recall the topic of the discussion.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"mc",q:"What is the most common professional email closing?",opts:["Cordialement","Bisous","Salut","Ciao"],ans:"Cordialement",hint:"A neutral, polite word used in almost every work email"},
        {type:"mc",q:"'Veuillez trouver ci-joint' is used when you:",opts:["request a meeting","attach a document to an email","apologize for a delay","ask for a raise"],ans:"attach a document to an email",hint:"Directing attention to something included with the message"},
        {type:"fb",opts:["Madame","Bonjour","Salut","Cordialement"],hint:"Formal greeting for an unknown recipient",s:"{1}, Monsieur, je vous écris au sujet de ma candidature.",a:["Madame"]},
        {type:"mc",q:"Which closing is the MOST formal?",opts:["Bien à vous","Cordialement","Je vous prie d'agréer mes salutations distinguées","Bonne journée"],ans:"Je vous prie d'agréer mes salutations distinguées",hint:"The longest and most elaborate traditional formula"},
        {type:"fb",opts:["Veuillez","Pouvez","Merci","Bonjour"],hint:"A very formal way of saying please, from the verb vouloir",s:"{1} trouver ci-joint mon rapport mensuel.",a:["Veuillez"]},
        {type:"match",pairs:[{trg:"Cordialement",src:"Kind regards"},{trg:"Madame, Monsieur",src:"Dear Sir/Madam"},{trg:"Veuillez",src:"Please (formal)"},{trg:"ci-joint",src:"attached"}]},
        {type:"mc",q:"'Suite à notre conversation' is used to:",opts:["schedule a meeting","end a conversation","introduce yourself","refer back to a previous discussion"],ans:"refer back to a previous discussion",hint:"An opening phrase that connects to something said before"},
        {type:"fb",opts:["Suite","Grâce","Merci","Selon"],hint:"A word meaning following or as a result of",s:"{1} à notre conversation, je vous envoie le dossier.",a:["Suite"]},
        {type:"fb",opts:["ci-joint","cordialement","cher","bien"],hint:"The adverb meaning 'attached herewith' in formal email language.",s:"Veuillez trouver {1} mon CV.",a:["ci-joint"]},
        {type:"mc",q:"How do you close a formal French email?",opts:["Cordialement","Bisous","Salut","À plus"],ans:"Cordialement",hint:"The formal closing word derived from the root meaning 'cordial/warm'."},
        {type:"fb",opts:["prie","demande","dit","écrit"],hint:"A very formal closing formula. Je vous ___ de = I beg/ask you to.",s:"Je vous {1} de bien vouloir accepter mes salutations.",a:["prie"]},
        {type:"mc",q:"In a formal French email, you should use:",opts:["tu (informal you)","vous (formal you)","on (we/people)","je (I) only"],ans:"vous (formal you)",hint:"The pronoun that shows respect and professional distance"}
  ]},
  {id:"fre23l5",title:"Les verbes du travail",icon:"⚙️",xp:15,board:true,steps:[
        {type:"intro",title:"Les verbes du travail",desc:"Learn essential workplace action verbs and how to use them.",goals:["Use professional action verbs","Conjugate workplace verbs","Describe work responsibilities"]},
        {type:"teach",trg:"gérer",src:"to manage / to handle",pos:"verb",gender:null,phonetic:"zhay-RAY",note:"Regular -er verb with accent change.\nJe gère, tu gères, il gère, nous gérons.",example:"A: Qu'est-ce que tu fais exactement?\nB: Je gère une équipe de dix personnes.\nA: Tu gères aussi le budget?\nB: Oui, je gère le budget et les plannings.",exampleSrc:"A: What exactly do you do?\nB: I manage a team of ten people.\nA: Do you also manage the budget?\nB: Yes, I manage the budget and the schedules.",funFact:"A regular -er verb, the most common French verb group (~90% of all verbs)."},
        {type:"teach",trg:"planifier",src:"to plan / to schedule",pos:"verb",gender:null,phonetic:"pla-nee-FYAY",note:"Regular -er verb. Planifier = to plan.\nAlso: prévoir (to foresee/plan ahead).",example:"A: Tu as planifié la réunion?\nB: Oui, j'ai tout planifié pour lundi.\nA: À quelle heure?\nB: J'ai planifié la réunion à neuf heures.",exampleSrc:"A: Did you plan the meeting?\nB: Yes, I planned everything for Monday.\nA: At what time?\nB: I scheduled the meeting at nine o'clock.",funFact:"A regular -er verb, the most common French verb group (~90% of all verbs)."},
        {type:"teach",trg:"organiser",src:"to organize",pos:"verb",gender:null,phonetic:"or-ga-nee-ZAY",note:"Regular -er verb. Organiser = to organize.\nBien organisé(e) = well organized.",example:"A: Qui organise la conférence?\nB: C'est Marie qui organise tout.\nA: Elle a besoin d'aide?\nB: Non, elle est très bien organisée.",exampleSrc:"A: Who is organizing the conference?\nB: Marie is organizing everything.\nA: Does she need help?\nB: No, she is very well organized.",funFact:"A regular -er verb, the most common French verb group (~90% of all verbs)."},
        {type:"teach",trg:"résoudre",src:"to solve / to resolve",pos:"verb",gender:null,phonetic:"ray-ZOODR",note:"Irregular verb. Je résous, tu résous, il résout.\nPassé composé: j'ai résolu.",example:"A: Il y a un problème avec le système.\nB: On doit résoudre ce problème rapidement.\nA: Tu sais comment le résoudre?\nB: Je pense avoir trouvé une solution.",exampleSrc:"A: There's a problem with the system.\nB: We need to solve this problem quickly.\nA: Do you know how to solve it?\nB: I think I've found a solution.",funFact:"A -re verb, the smallest of the three regular verb groups."},
        {type:"teach",trg:"collaborer",src:"to collaborate",pos:"verb",gender:null,phonetic:"ko-la-bo-RAY",note:"Regular -er verb. Collaborer avec = to collaborate with.\nLa collaboration = the collaboration.",example:"A: Vous collaborez avec d'autres équipes?\nB: Oui, on collabore avec le service marketing.\nA: Ça se passe bien?\nB: Très bien, c'est enrichissant de collaborer.",exampleSrc:"A: Do you collaborate with other teams?\nB: Yes, we collaborate with the marketing department.\nA: Does it go well?\nB: Very well, it's rewarding to collaborate.",funFact:"A regular -er verb, the most common French verb group (~90% of all verbs)."},
        {type:"teach",trg:"diriger",src:"to lead / to manage / to direct",pos:"verb",gender:null,phonetic:"dee-ree-ZHAY",note:"Regular -er verb with spelling change: nous dirigeons.\nDiriger = to lead, to run, to direct.",example:"A: Qui dirige ce département?\nB: C'est Monsieur Laurent qui dirige l'équipe.\nA: Depuis combien de temps?\nB: Il dirige le département depuis cinq ans.",exampleSrc:"A: Who leads this department?\nB: Mr. Laurent leads the team.\nA: For how long?\nB: He has been leading the department for five years.",funFact:"A regular -er verb, the most common French verb group (~90% of all verbs)."},
        {type:"mc",q:"Which verb means 'to solve'?",opts:["résoudre","gérer","planifier","collaborer"],ans:"résoudre",hint:"Finding an answer to a problem or difficulty"},
        {type:"fb",opts:["gère","planifie","collabore","résout"],hint:"Being responsible for overseeing people and resources",s:"Elle {1} une équipe de vingt personnes.",a:["gère"]},
        {type:"mc",q:"What is the past participle of 'résoudre'?",opts:["résous","résolu","résoudé","résolvé"],ans:"résolu",hint:"An irregular form, not following standard patterns"},
        {type:"fb",opts:["collaborer","résoudre","diriger","gérer"],hint:"Working together with another team on shared goals",s:"Nous devons {1} avec le service informatique.",a:["collaborer"]},
        {type:"match",pairs:[{trg:"gérer",src:"to manage"},{trg:"planifier",src:"to plan"},{trg:"organiser",src:"to organize"},{trg:"résoudre",src:"to solve"},{trg:"diriger",src:"to lead"}]},
        {type:"mc",q:"'Nous dirigeons' is the nous form of:",opts:["organiser","gérer","diriger","résoudre"],ans:"diriger",hint:"This verb adds an e before -ons to keep the soft g sound"},
        {type:"fb",opts:["planifié","résolu","dirigé","collaboré"],hint:"Setting up the time and details for a scheduled event",s:"J'ai {1} la réunion pour vendredi après-midi.",a:["planifié"]},
        {type:"fb",opts:["gérer","postuler","embaucher","planifier"],hint:"The infinitive meaning 'to manage' people or resources at work.",s:"Elle doit {1} une équipe de dix personnes.",a:["gérer"]},
        {type:"mc",q:"Which verb means 'to solve a problem'?",opts:["Diriger","Planifier","Collaborer","Résoudre"],ans:"Résoudre",hint:"This verb is irregular. Past participle: résolu. Meaning: to find a solution."},
        {type:"fb",opts:["collaborer","résoudre","diriger","embaucher"],hint:"The verb meaning 'to work together with' another team or group.",s:"Nous devons {1} avec l'équipe de Paris.",a:["collaborer"]},
        {type:"mc",q:"Which verb would you use for 'She runs the company'?",opts:["Elle dirige l'entreprise.","Elle collabore l'entreprise.","Elle planifie l'entreprise.","Elle résout l'entreprise."],ans:"Elle dirige l'entreprise.",hint:"Being at the top, making the big decisions"}
  ]},
  {id:"fre23l6",title:"La culture du travail",icon:"🇫🇷",xp:15,board:true,steps:[
        {type:"intro",title:"La culture du travail",desc:"Discover what makes French work culture unique: holidays, breaks, and workers' rights.",goals:["Discuss French work culture topics","Understand les congés payés and RTT","Talk about workplace traditions"]},
        {type:"teach",trg:"les congés payés",src:"paid vacation / paid leave",pos:"noun",gender:"pl",phonetic:"lay kon-ZHAY pay-YAY",note:"Masculine plural. 5 weeks minimum by law.\nAlso: les vacances = holidays (general).",example:"A: Combien de congés payés as-tu?\nB: En France, on a cinq semaines de congés payés.\nA: Cinq semaines? C'est beaucoup!\nB: Oui, c'est un droit pour tous les salariés.",exampleSrc:"A: How much paid vacation do you have?\nB: In France, we have five weeks of paid vacation.\nA: Five weeks? That's a lot!\nB: Yes, it's a right for all employees.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"les RTT",src:"extra days off (reduced working time)",pos:"noun",gender:"pl",phonetic:"lay air-tay-TAY",note:"Stands for Réduction du Temps de Travail.\nExtra days off for those working over 35 hours.",example:"A: Tu prends un RTT vendredi?\nB: Oui, j'ai encore trois jours de RTT.\nA: C'est en plus des congés payés?\nB: Oui, les RTT s'ajoutent aux cinq semaines.",exampleSrc:"A: Are you taking an RTT day Friday?\nB: Yes, I still have three RTT days left.\nA: Is that on top of paid vacation?\nB: Yes, RTT days are added to the five weeks.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"la pause déjeuner",src:"the lunch break",pos:"noun",gender:"f",phonetic:"lah POHZ day-zhuh-NAY",note:"Feminine. French lunch breaks are sacred.\nTypically one hour, sometimes 90 minutes.",example:"A: La pause déjeuner dure combien de temps?\nB: En général, une heure minimum.\nA: Vous mangez où?\nB: Souvent au restaurant ou à la cantine.",exampleSrc:"A: How long is the lunch break?\nB: Usually, one hour minimum.\nA: Where do you eat?\nB: Often at a restaurant or the canteen.",funFact:"Feminine noun. Words ending in -tion, -sion, -ure are usually feminine."},
        {type:"teach",trg:"le comité d'entreprise",src:"the works council / staff committee",pos:"noun",gender:"m",phonetic:"luh ko-mee-TAY don-truh-PREEZ",note:"Now officially called CSE (Comité Social et Economique).\nProvides benefits and activities for employees.",example:"A: Tu connais le comité d'entreprise?\nB: Oui, il organise des activités pour les employés.\nA: Comme quoi?\nB: Des sorties, des réductions, des cadeaux de Noël.",exampleSrc:"A: Do you know the works council?\nB: Yes, it organizes activities for employees.\nA: Like what?\nB: Outings, discounts, Christmas gifts.",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"teach",trg:"les 35 heures",src:"the 35-hour workweek",pos:"noun",gender:"pl",phonetic:"lay tront-SANK UHR",note:"The legal workweek in France since 2000.\nWorking beyond 35h generates RTT or overtime.",example:"A: En France, on travaille 35 heures par semaine?\nB: C'est la durée légale, oui.\nA: Et si on travaille plus?\nB: On reçoit des RTT ou des heures supplémentaires.",exampleSrc:"A: In France, you work 35 hours per week?\nB: That's the legal duration, yes.\nA: And if you work more?\nB: You get RTT days or overtime pay.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"mc",q:"How many weeks of paid vacation do French employees get minimum?",opts:["five weeks","two weeks","three weeks","four weeks"],ans:"five weeks",hint:"A generous amount guaranteed by French labor law"},
        {type:"mc",q:"What does RTT stand for?",opts:["Repos Total du Travail","Réduction du Temps de Travail","Remplacement Temporaire du Travail","Régulation du Temps de Travail"],ans:"Réduction du Temps de Travail",hint:"Three words about making working hours shorter"},
        {type:"fb",opts:["35","40","38","42"],hint:"A number below 40, introduced in the year 2000",s:"En France, la durée légale du travail est de {1} heures par semaine.",a:["35"]},
        {type:"mc",q:"What is 'la pause déjeuner' typically like in France?",opts:["Skipped most days","15 minutes at the desk","At least one hour, often a real meal","Only 30 minutes"],ans:"At least one hour, often a real meal",hint:"The French take this midday break very seriously"},
        {type:"fb",opts:["comité","patron","collègue","bureau"],hint:"A group representing worker interests and organizing perks",s:"Le {1} d'entreprise organise des activités pour les employés.",a:["comité"]},
        {type:"match",pairs:[
          {trg:"les congés payés",src:"paid vacation"},
          {trg:"les RTT",src:"extra days off"},
          {trg:"la pause déjeuner",src:"the lunch break"},
          {trg:"les 35 heures",src:"the 35-hour week"},
          {trg:"le comité d'entreprise",src:"the works council"}
        ]},
        {type:"mc",q:"Les RTT are available to employees who:",opts:["work part-time","have been with the company 10+ years","are in management positions only","work more than 35 hours per week"],ans:"work more than 35 hours per week",hint:"Compensation for exceeding the legal ___ly limit"},
        {type:"fb",opts:["congés","réunions","rapports","projets"],hint:"Days off that every employee is entitled to by law",s:"J'ai encore trois jours de {1} à prendre avant la fin du mois.",a:["congés"]},
        {type:"mc",q:"How many weeks of congés payés do French workers get minimum?",opts:["5 weeks","2 weeks","3 weeks","4 weeks"],ans:"5 weeks",hint:"France is known for generous paid leave. The legal minimum is quite high."},
        {type:"fb",opts:["35","40","38","45"],hint:"The famous French weekly hour limit, shorter than most countries.",s:"En France, la semaine de travail est de {1} heures.",a:["35"]},
        {type:"mc",q:"What does RTT stand for in French work culture?",opts:["Repos total du travailleur","Réduction du temps de travail","Règlement des tâches du travail","Rémunération du temps de travail"],ans:"Réduction du temps de travail",hint:"Extra days off created when employees work more than the legal weekly limit."},
        {type:"mc",q:"Which statement about French work culture is true?",opts:["Lunch breaks are not common in France.","Most people eat at their desk in 10 minutes.","Lunch is considered an important daily ritual.","Only managers get a real lunch break."],ans:"Lunch is considered an important daily ritual.",hint:"Food and shared meals are deeply valued in French society"}
  ]},
  {id:"fre23l7",title:"L'entretien d'embauche",icon:"🎤",xp:15,board:true,steps:[
        {type:"intro",title:"L'entretien d'embauche",desc:"Prepare for a job interview in French with key phrases and strategies.",goals:["Answer common interview questions","Present qualifications confidently","Use formal register appropriately"]},
        {type:"teach",trg:"Pourquoi ce poste vous intéresse-t-il?",src:"Why are you interested in this position?",pos:"intj",gender:null,phonetic:"poor-KWAH suh POST voo zan-tay-RES-teel",note:"Classic interview question.\nAlways answer with specific reasons.",example:"A: Pourquoi ce poste vous intéresse-t-il?\nB: Ce poste m'intéresse parce qu'il combine mes compétences.\nA: Quelles compétences exactement?\nB: La gestion de projet et le travail d'équipe.",exampleSrc:"A: Why are you interested in this position?\nB: This position interests me because it combines my skills.\nA: Which skills exactly?\nB: Project management and teamwork.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"teach",trg:"Quelles sont vos qualités?",src:"What are your strengths?",pos:"intj",gender:null,phonetic:"kel son voh ka-lee-TAY",note:"Expect this question in every French interview.\nGive 2-3 qualities with concrete examples.",example:"A: Quelles sont vos qualités?\nB: Je suis organisé, rigoureux et créatif.\nA: Pouvez-vous donner un exemple?\nB: J'ai organisé un projet de A à Z l'année dernière.",exampleSrc:"A: What are your strengths?\nB: I am organized, thorough, and creative.\nA: Can you give an example?\nB: I organized a project from start to finish last year.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"teach",trg:"Parlez-moi de votre expérience.",src:"Tell me about your experience.",pos:"intj",gender:null,phonetic:"par-LAY mwah duh votr eks-pay-RYONS",note:"Use this structure: years + field + company type.\nKeep it focused and relevant to the role.",example:"A: Parlez-moi de votre expérience.\nB: J'ai cinq ans d'expérience en marketing digital.\nA: Dans quel type d'entreprise?\nB: J'ai travaillé dans une start-up puis dans un grand groupe.",exampleSrc:"A: Tell me about your experience.\nB: I have five years of experience in digital marketing.\nA: In what type of company?\nB: I worked in a startup and then in a large corporation.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"teach",trg:"Quand pouvez-vous commencer?",src:"When can you start?",pos:"intj",gender:null,phonetic:"kon poo-VAY voo ko-mon-SAY",note:"Le préavis = the notice period.\nUsually 1-3 months in France.",example:"A: Quand pouvez-vous commencer?\nB: Je peux commencer dans un mois.\nA: Pas avant?\nB: Je dois respecter mon préavis, malheureusement.",exampleSrc:"A: When can you start?\nB: I can start in one month.\nA: Not sooner?\nB: I have to respect my notice period, unfortunately.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"teach",trg:"Avez-vous des questions?",src:"Do you have any questions?",pos:"intj",gender:null,phonetic:"a-VAY voo day kes-TYON",note:"Always ask questions at the end of an interview.\nShows motivation and genuine interest.",example:"A: Avez-vous des questions?\nB: Oui, comment est l'ambiance dans l'équipe?\nA: Très bonne, on organise souvent des sorties.\nB: C'est important pour moi, merci.",exampleSrc:"A: Do you have any questions?\nB: Yes, what is the team atmosphere like?\nA: Very good, we often organize outings.\nB: That's important to me, thank you.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"mc",q:"What should you do when asked 'Quelles sont vos qualités?'",opts:["Give 2-3 qualities with examples","Say you have no weaknesses","List 10 qualities quickly","Say you prefer not to answer"],ans:"Give 2-3 qualities with examples",hint:"Specific evidence makes your answer more convincing"},
        {type:"fb",opts:["intéresse-t-il","plaît-il","convient-il","attend-il"],hint:"A formal way of asking about someone's interest using inversion",s:"Pourquoi ce poste vous {1}?",a:["intéresse-t-il"]},
        {type:"mc",q:"What is 'le préavis'?",opts:["the first day of work","the notice period before leaving a job","the salary negotiation","the job description"],ans:"the notice period before leaving a job",hint:"A required time between resignation and actually ___"},
        {type:"fb",opts:["Parlez-moi","Dites-moi","Montrez-moi","Écrivez-moi"],hint:"A request starting with the imperative of parler + a pronoun",s:"{1} de votre expérience professionnelle.",a:["Parlez-moi"]},
        {type:"mc",q:"At the end of an interview, you should:",opts:["Ask about salary immediately","Say you have no questions","Ask thoughtful questions about the role or team","Leave as quickly as possible"],ans:"Ask thoughtful questions about the role or team",hint:"Showing curiosity demonstrates genuine motivation"},
        {type:"match",pairs:[
          {trg:"vos qualités",src:"your strengths"},
          {trg:"votre expérience",src:"your experience"},
          {trg:"le préavis",src:"the notice period"},
          {trg:"commencer",src:"to start"},
          {trg:"des questions",src:"some questions"}
        ]},
        {type:"fb",opts:["commencer","finir","postuler","diriger"],hint:"The action of beginning a new role at a company",s:"Je peux {1} dans un mois, après mon préavis.",a:["commencer"]},
        {type:"mc",q:"Which is the best answer to 'Parlez-moi de votre expérience'?",opts:["Je préfère ne pas en parler.","Je n'ai pas beaucoup d'expérience.","Mon expérience est longue et compliquée.","J'ai cinq ans d'expérience en marketing dans une grande entreprise."],ans:"J'ai cinq ans d'expérience en marketing dans une grande entreprise.",hint:"Structure your response with years, field, and context"},
        {type:"fb",opts:["rejoindre","quitter","gérer","résoudre"],hint:"The infinitive meaning 'to join' when asked about your motivation.",s:"Pourquoi voulez-vous {1} notre entreprise?",a:["rejoindre"]},
        {type:"mc",q:"In a French interview, what should you call the interviewer?",opts:["Monsieur/Madame","Tu","Prénom","Chef"],ans:"Monsieur/Madame",hint:"The formal address terms. Never use the informal pronoun in interviews."},
        {type:"fb",opts:["atout","défaut","congé","salaire"],hint:"The masculine noun meaning 'strength/asset' when describing your qualities.",s:"Mon plus grand {1} est ma capacité à travailler en équipe.",a:["atout"]},
        {type:"mc",q:"'Rigoureux' as a quality means:",opts:["relaxed and easygoing","thorough and precise","creative and artistic","fast and efficient"],ans:"thorough and precise",hint:"Someone who pays careful attention to detail and accuracy"}
  ]},
  {id:"fre23l8",title:"Révision: Le travail",icon:"🔄",xp:15,board:true,steps:[
        {type:"intro",title:"Révision: Le travail",desc:"Review everything you learned about French work culture and professional life.",goals:["Review all work vocabulary","Apply professional phrases in context","Demonstrate mastery of workplace French"]},
        {type:"mc",q:"What is 'une entreprise'?",opts:["a company","an office","a salary","a meeting"],ans:"a company",hint:"The organization that employs people as a whole"},
        {type:"fb",opts:["candidature","réunion","entreprise","qualité"],hint:"The complete set of documents submitted for a job",s:"Elle a envoyé sa {1} pour le poste de directrice.",a:["candidature"]},
        {type:"mc",q:"Which closing is appropriate for a professional email?",opts:["Bisous","Cordialement","À plus","Ciao"],ans:"Cordialement",hint:"The standard neutral sign-off in French business correspondence"},
        {type:"fb",opts:["patron","collègue","salaire","bureau"],hint:"The person who is in charge of you at work",s:"Mon {1} est très exigeant mais juste.",a:["patron"]},
        {type:"mc",q:"What does 'gérer' mean?",opts:["to plan","to solve","to manage","to organize"],ans:"to manage",hint:"Overseeing people, budgets, or resources as a responsibility"},
        {type:"match",pairs:[{trg:"le poste",src:"the position"},{trg:"le délai",src:"the deadline"},{trg:"embaucher",src:"to hire"},{trg:"résoudre",src:"to solve"},{trg:"les congés payés",src:"paid vacation"}]},
        {type:"fb",opts:["résoudre","gérer","planifier","postuler"],hint:"Finding an answer or fix for a difficult situation",s:"Nous devons {1} ce problème avant vendredi.",a:["résoudre"]},
        {type:"mc",q:"How many weeks of paid vacation do French employees get by law?",opts:["Two","Three","Four","Five"],ans:"Five",hint:"A generous number that surprises many visitors"},
        {type:"fb",opts:["Veuillez","Pouvez","Merci","Bonjour"],hint:"The most formal way to say please in a business letter",s:"{1} trouver ci-joint le rapport mensuel.",a:["Veuillez"]},
        {type:"mc",q:"What are 'les RTT'?",opts:["Extra days off for exceeding 35 hours","Vacation days for managers only","Sick leave days","Overtime payment"],ans:"Extra days off for exceeding 35 hours",hint:"Compensation in time rather than money for longer weeks"},
        {type:"fb",opts:["entretien","rapport","dossier","planning"],hint:"A formal face-to-face conversation, often about a job",s:"J'ai un {1} avec le directeur demain matin.",a:["entretien"]},
        {type:"mc",q:"Which verb means 'to collaborate'?",opts:["diriger","collaborer","résoudre","embaucher"],ans:"collaborer",hint:"Working jointly with others toward a shared objective"},
        {type:"match",pairs:[
          {trg:"la réunion",src:"the meeting"},
          {trg:"le rapport",src:"the report"},
          {trg:"diriger",src:"to lead"},
          {trg:"la pause déjeuner",src:"the lunch break"},
          {trg:"la lettre de motivation",src:"the cover letter"}
        ]},
        {type:"fb",opts:["qualités","questions","expériences","candidatures"],hint:"Personal strengths that make you a good employee",s:"Quelles sont vos {1}? Je suis organisé et créatif.",a:["qualités"]},
        {type:"mc",q:"'Suite à notre conversation' is used to:",opts:["introduce yourself","close a formal letter","open a follow-up email","request time off"],ans:"open a follow-up email",hint:"Connecting a written message to a prior spoken exchange"},
        {type:"fb",opts:["comité","patron","bureau","projet"],hint:"An elected group that arranges benefits for all workers",s:"Le {1} d'entreprise organise des sorties et des activités.",a:["comité"]},
        {type:"mc",q:"Which is correct for 'I manage the team'?",opts:["Je collabore l'équipe.","Je résous l'équipe.","Je planifie l'équipe.","Je gère l'équipe."],ans:"Je gère l'équipe.",hint:"The verb for being responsible for overseeing a group"},
        {type:"fb",opts:["35","40","38","45"],hint:"Below 40, a number established by French law in 2000",s:"La durée légale du travail en France est de {1} heures.",a:["35"]},
        {type:"mc",q:"In a French job interview, 'le préavis' refers to:",opts:["the notice period before leaving your current job","the first interview round","the salary offer","the probation period"],ans:"the notice period before leaving your current job",hint:"A mandatory waiting time between resignation and departure"}
  ]},
  {id:"fre23l8b",title:"Sentiments et Opinions",icon:"💭",xp:20,board:true,steps:[
        {type:"intro",title:"Expanded Feelings & Opinions",desc:"Des mots pour exprimer des émotions et des opinions nuancées.\nLearn advanced vocabulary for feelings and opinions in French.",goals:["Learn 12 expanded emotion words","Express nuanced feelings in French","Discuss masculine and feminine forms"]},
        {type:"teach",trg:"frustré(e)",src:"frustrated",pos:"adj",gender:null,note:"frustré (m.), frustrée (f.)\nêtre frustré(e) par quelque chose.\nla frustration (frustration).",example:"A: Tu as l'air frustré. Ça va ?\nB: Oui, mon ordinateur ne marche plus.\nA: Depuis quand ?\nB: Depuis ce matin. Je suis très frustré.",exampleSrc:"A: You look frustrated. Are you OK?\nB: Yes, my computer isn't working anymore.\nA: Since when?\nB: Since this morning. I'm very frustrated.",funFact:"Cognate with English 'frustrated'. Many English words were borrowed from French after 1066."},
        {type:"teach",trg:"confiant(e)",src:"confident",pos:"adj",gender:null,note:"confiant (m.), confiante (f.)\nAlso: sûr(e) de soi (self-assured).\nla confiance (confidence, trust).",example:"A: Tu es confiant pour l'examen ?\nB: Oui, j'ai bien révisé.\nA: C'est bien d'être confiant.\nB: Mais pas trop, il faut rester concentré.",exampleSrc:"A: Are you confident about the exam?\nB: Yes, I studied well.\nA: It's good to be confident.\nB: But not too much, you have to stay focused.",funFact:"French adjectives agree in gender and number with their noun. Most add -e for feminine."},
        {type:"teach",trg:"déçu(e)",src:"disappointed",pos:"adj",gender:null,note:"déçu (m.), déçue (f.)\nêtre déçu(e) de/par (to be disappointed in/by).\nla déception (disappointment).",example:"A: Tu as l'air déçu.\nB: Oui, je n'ai pas eu le poste.\nA: C'est dommage, tu étais un bon candidat.\nB: Merci, je vais continuer à chercher.",exampleSrc:"A: You look disappointed.\nB: Yes, I didn't get the job.\nA: That's a shame, you were a good candidate.\nB: Thanks, I'll keep looking.",funFact:"French adjectives agree in gender and number with their noun. Most add -e for feminine."},
        {type:"teach",trg:"impressionné(e)",src:"impressed",pos:"adj",gender:null,note:"impressionné (m.), impressionnée (f.)\nêtre impressionné(e) par (to be impressed by).\nimpressionner (to impress).",example:"A: Je suis impressionné par ton travail.\nB: Merci, c'est gentil de dire ça.\nA: Tu as fait beaucoup de progrès.\nB: J'ai travaillé dur ces derniers mois.",exampleSrc:"A: I'm impressed by your work.\nB: Thanks, that's kind of you to say.\nA: You've made a lot of progress.\nB: I worked hard these past months.",funFact:"French adjectives agree in gender and number with their noun. Most add -e for feminine."},
        {type:"teach",trg:"confus(e)",src:"confused",pos:"adj",gender:null,note:"confus (m.), confuse (f.)\nAlso: perdu(e) (lost, confused).\nla confusion (confusion).",example:"A: Les instructions sont confuses.\nB: Oui, je ne comprends rien.\nA: On devrait demander au professeur.\nB: Bonne idée, je suis complètement perdu.",exampleSrc:"A: The instructions are confusing.\nB: Yes, I don't understand anything.\nA: We should ask the professor.\nB: Good idea, I'm completely lost.",funFact:"Cognate with English 'confused'. Many English words were borrowed from French after 1066."},
        {type:"teach",trg:"regretter",src:"to regret",pos:"verb",gender:null,note:"regretter (verb)\nle regret (m.) (regret, noun).\nJe regrette de... (I regret that...).",example:"A: Tu regrettes ta décision ?\nB: Un peu, oui. J'aurais dû réfléchir plus.\nA: C'est normal d'avoir des regrets.\nB: La prochaine fois, je serai plus prudent.",exampleSrc:"A: Do you regret your decision?\nB: A little, yes. I should have thought more.\nA: It's normal to have regrets.\nB: Next time, I'll be more careful.",funFact:"A regular -er verb, the most common French verb group (~90% of all verbs)."},
        {type:"teach",trg:"avoir hâte de",src:"to look forward to",pos:"verb",gender:null,note:"avoir hâte de + infinitive\nJ'ai hâte de te voir. (I can't wait to see you.)\nAlso: être impatient(e) de.",example:"A: Tu as hâte d'être en vacances ?\nB: Oh oui, j'ai vraiment hâte !\nA: Tu pars où ?\nB: En Espagne, au bord de la mer.",exampleSrc:"A: Are you looking forward to the holidays?\nB: Oh yes, I really can't wait!\nA: Where are you going?\nB: To Spain, by the sea.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"teach",trg:"anxieux / anxieuse",src:"anxious",pos:"adj",gender:null,note:"anxieux (m.), anxieuse (f.)\nl'anxiété (f.) (anxiety).\navoir le trac (to have stage fright).",example:"A: Tu es anxieuse avant la présentation ?\nB: Oui, un peu. J'ai le trac.\nA: Respire profondément, ça va bien se passer.\nB: Merci, ça me rassure.",exampleSrc:"A: Are you anxious before the presentation?\nB: Yes, a little. I have stage fright.\nA: Breathe deeply, it will go well.\nB: Thanks, that reassures me.",funFact:"French adjectives agree in gender and number with their noun. Most add -e for feminine."},
        {type:"teach",trg:"satisfait(e)",src:"satisfied",pos:"adj",gender:null,note:"satisfait (m.), satisfaite (f.)\nêtre satisfait(e) de (to be satisfied with).\nla satisfaction (satisfaction).",example:"A: Tu es satisfait du résultat ?\nB: Oui, c'est exactement ce que je voulais.\nA: Le client est content aussi ?\nB: Oui, il est très satisfait.",exampleSrc:"A: Are you satisfied with the result?\nB: Yes, it's exactly what I wanted.\nA: Is the client happy too?\nB: Yes, he is very satisfied.",funFact:"Cognate with English 'satisfied'. Many English words were borrowed from French after 1066."},
        {type:"teach",trg:"tendu(e)",src:"tense / stressed",pos:"adj",gender:null,note:"tendu (m.), tendue (f.)\nAlso: nerveux/nerveuse (nervous).\nla tension (tension, stress).",example:"A: L'atmosphère au bureau est tendue.\nB: Oui, tout le monde est stressé.\nA: C'est à cause du nouveau projet ?\nB: Oui, les délais sont très courts.",exampleSrc:"A: The atmosphere at the office is tense.\nB: Yes, everyone is stressed.\nA: Is it because of the new project?\nB: Yes, the deadlines are very tight.",funFact:"French adjectives agree in gender and number with their noun. Most add -e for feminine."},
        {type:"teach",trg:"jaloux / jalouse",src:"jealous",pos:"adj",gender:null,note:"jaloux (m.), jalouse (f.)\nla jalousie (jealousy).\nêtre jaloux/jalouse de (to be jealous of).",example:"A: Tu es jalouse de ta collègue ?\nB: Non, pas vraiment. Je suis contente pour elle.\nA: C'est bien d'être comme ça.\nB: La jalousie ne sert à rien.",exampleSrc:"A: Are you jealous of your colleague?\nB: No, not really. I'm happy for her.\nA: It's good to be like that.\nB: Jealousy doesn't help anything.",funFact:"French adjectives agree in gender and number with their noun. Most add -e for feminine."},
        {type:"teach",trg:"reconnaissant(e)",src:"grateful",pos:"adj",gender:null,note:"reconnaissant (m.), reconnaissante (f.)\nla reconnaissance (gratitude).\nêtre reconnaissant(e) envers (to be grateful toward).",example:"A: Je suis très reconnaissant pour ton aide.\nB: De rien, c'est normal entre amis.\nA: Sans toi, je n'aurais pas réussi.\nB: Ça me fait plaisir de t'aider.",exampleSrc:"A: I'm very grateful for your help.\nB: You're welcome, that's normal between friends.\nA: Without you, I wouldn't have succeeded.\nB: It's my pleasure to help you.",funFact:"French adjectives agree in gender and number with their noun. Most add -e for feminine."},
        {type:"tip",title:"Expressing Feelings with Être",deepDive:"Some feelings use avoir:\navoir hâte de (to look forward to)\navoir peur (to be afraid)\navoir honte (to be ashamed)\n\nRegretter is a regular -er verb:\nJe regrette, tu regrettes, il/elle regrette.\nPassé composé: J'ai regretté.",text:"Most feelings use être + adjective:\n\nJe suis frustré(e). (I am frustrated.)\nElle est déçue. (She is disappointed.)\nIl est confiant. (He is confident.)\n\nRemember gender agreement:\nmasculine: frustré, déçu, confiant\nfeminine: frustrée, déçue, confiante"},
        {type:"mc",q:"Which word means 'disappointed' in French?",opts:["déçu(e)","frustré(e)","confiant(e)","satisfait(e)"],ans:"déçu(e)",hint:"The feeling when something you hoped for did not happen."},
        {type:"mc",q:"'Avoir hâte de' means:",opts:["to regret","to look forward to","to be jealous","to be confused"],ans:"to look forward to",hint:"An expression about excitement for something in the future."},
        {type:"fb",opts:["impressionnée","confuse","tendue","jalouse"],hint:"Feeling admiration because something exceeded expectations.",s:"Elle est très {1} par les résultats de son équipe.",a:["impressionnée"]},
        {type:"fb",opts:["confus","satisfait","reconnaissant","confiant"],hint:"A state of not understanding what is happening.",s:"Il est {1} parce qu'il ne comprend pas les instructions.",a:["confus"]},
        {type:"mc",q:"What does 'reconnaissant(e)' mean?",opts:["tense","anxious","grateful","jealous"],ans:"grateful",hint:"A warm feeling of thanks toward someone who helped you."},
        {type:"match",pairs:[{trg:"frustré(e)",src:"frustrated"},{trg:"confiant(e)",src:"confident"},{trg:"anxieux/anxieuse",src:"anxious"},{trg:"jaloux/jalouse",src:"jealous"},{trg:"satisfait(e)",src:"satisfied"}]},
        {type:"fb",opts:["regrette","impressionne","satisfais","confie"],hint:"A verb meaning to wish you had not done something.",s:"Je {1} d'avoir dit ça. J'aurais dû me taire.",a:["regrette"]},
        {type:"drag_fill",hint:"She believes in herself but also feels some nervousness.",s:"Elle est {1} pour l'entretien mais aussi un peu {2}.",blanks:{"1":"confiante","2":"anxieuse"},pool:["confiante","anxieuse","jalouse","reconnaissante"]},
        {type:"mc",q:"Which sentence uses 'tendu(e)' correctly?",opts:["Nous avons tendu le restaurant.","J'ai tendu mes vacances.","Elle est tendue pour ses amis.","L'ambiance est tendue au travail."],ans:"L'ambiance est tendue au travail.",hint:"This adjective describes a stressful or uncomfortable atmosphere."},
        {type:"mc",q:"How do you say 'I can't wait to see you' in French?",opts:["J'ai hâte de te voir.","Je regrette de te voir.","Je suis confus de te voir.","Je suis jaloux de te voir."],ans:"J'ai hâte de te voir.",hint:"Use the expression with 'a___' that expresses eager anticipation."}
  ]}
]};
